VALUES
  ('aboriginal-10ced7e2-moex-00116', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '依現行法規定，下列何者非屬依法得予以資遣之人員？', '["機關裁撤時，已任職滿20年之公務人員", "機關之業務緊縮時，尚不符合法定退休條件而須裁減之人員", "現職工作不適任，經調整其他相當工作後，仍未能達到要求標準者", "現職工作不適任者且本機關已無其他工作可予調任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00117', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '關於訴願管轄，下列敘述何者正確？', '["訴願事件，無論機關層級，均以原處分機關為訴願審理機關，俾以實現行政自我審查之目的", "委任事件之訴願管轄，應將委任機關認定為原處分機關，而向該委任機關或其直接上級機關提 起訴願", "委託事件之訴願管轄，應將委託機關視為原處分機關，而向該委託機關或其直接上級機關提起 訴願", "對於公平交易委員會所作成之行政處分不服，仍可提起訴願，又為維護獨立機關之獨立功能， 由公平交易委員會自行審理訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00118', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '關於行政罰之處罰對象，下列敘述何者正確？', '["非法人團體之管理人執行職務，因重大過失致該非法人團體違反行政法上義務而應受處罰時， 應並受同一規定罰鍰之處罰", "私法人之董事與私法人應併受處罰時，得由行政機關決定僅處罰該私法人", "主管機關以行政機關為處罰對象時，須得其上級機關之許可", "違反同一行政法上義務者有多數人時，得類推適用刑法上共同正犯之規定處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00119', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '下列何者不符合行政訴訟法調解程序之規定？', '["調解程序由調解委員主持為原則，法官認為適當時，亦可由法官主持", "訴願決定送達後、行政訴訟起訴前可開始進行調解", "行政法院得依職權通知第三人參加調解", "調解事項不限於行政訴訟標的，但須經法院許可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00120', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '依行政執行法規定，關於怠金之敘述，下列何者錯誤？', '["對於可代為履行之行為義務，亦得處以怠金", "對於不行為義務，亦得處以怠金", "怠金得與罰鍰併科，並無一事不二罰原則之適用", "怠金得與罰金併科，並無一事不二罰原則之適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00121', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '關於訴願之提起，下列敘述何者正確？', '["訴願之提起，應自行政處分達到或公告期滿之日起2個月內為之", "利害關係人提起訴願者，應自知悉行政處分時起算20日內為之", "訴願之提起，以原行政處分機關或受理訴願機關收受訴願書之日期為準", "訴願人誤向原行政處分機關或受理訴願機關以外之機關提起訴願者，以該機關收受之次日，視 為提起訴願之日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00122', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-113-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '下列何者非屬基於特別犧牲所成立之補償？', '["戒嚴時期人民因內亂罪被沒收財產，於受無罪判決確定後，無法發還該財產時而為之補償", "因土地徵收而為之補償", "疫情期間徵用防疫物資而為之補償", "主管機關對於既成道路在依法徵收或價購前，因埋設地下設施物而為之補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "374c42aebe29", "answer_pdf_sha1": "2bf0906c6799", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "404", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00123', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-112-13504c0c', 'sub-aboriginal-10ced7e2-05', NULL, 'essay', '短文寫作：（20分）
最後一哩路（ThelastMile）本是電信專用名詞，意指固網最後一
段連到家戶部分，由於終端家戶之間個別差異頗大，鋪設相當麻煩，
後引申為完成一件事情時的最終關鍵性步驟。這個詞已被廣泛使用，
例如運動選手在比賽的最後一局，或指攀爬高山最後的攻頂，亦有用
以描述即將畢業，面對就業考驗之前的在學時間等。「最後一哩路」，
似乎意指著成功就在眼前，但是失敗亦隨時虎視耽耽，是通向希望與
絕望的歧路，自己與自己的戰爭。請針對「最後一哩路」這個觀念，
提出自己的見解，並寫出自身的體驗與啟發。（文長不超過400字）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "106b6fd98758", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00124', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-112-13504c0c', 'sub-aboriginal-10ced7e2-05', NULL, 'essay', '作文：（60分）
語言或可視為作為人類的最重要的特徵，但「沉默」卻是古今中
外皆有的現象。徐志摩為康橋美景所震懾，他說：「不說也罷，說來
你們也是不信的！」魯迅則說：「當我沉默的時候，我覺得充實；我
將開口，同時感到空虛。」歌劇《魔笛》，男主角塔米諾（Tamino）
王子必須通過三種極端考驗，方可迎來光明，重建天地秩序，其中一
項試煉就是「沉默」。沉默者選擇隱藏聲音，主流者踴躍發聲，結果
形成了強者更強、弱者消音的進程。但有些時候，不說反而比說來得
更有力量，「於無聲處聽驚雷」，在某些狀態下，沉默成了最強韌的武
器，也是最難得的力量。請以「沉默的力量」為題，撰寫一篇文章。
乙、測驗部分：（20分） 代號：1101', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "106b6fd98758", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
  ('aboriginal-10ced7e2-moex-00125', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-112-f68e6f9e', 'sub-aboriginal-10ced7e2-06', NULL, 'essay', '許多人會因為網路負面攻訐而產生沮喪、甚至自殺輕生，然而，有些人
對這些網路負面訊息卻能一笑置之，不予理會。請從心理學「知覺
（perception）」的觀點說明為何有些人會受到負面訊息的影響，有些人
則不會？（10 分）那些心理因素會影響個體對訊息的知覺？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:04+00:00", "source_pdf_sha1": "6cef908b2a38", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "505", "s": "1009", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "心理學(包括諮商與輔導)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL)
